import jwt
from flask import Flask, request, jsonify, Response


app = Flask(__name__)
app.config['SECRET_KEY']='this is my secret key' #Change this!

@app.route('/api/v1/auth', methods=['POST'])
def get_token():

    auth = request.authorization
    
    if not auth or not auth.username == 'jose':
        return Response('Could not verify',401,{'WWW-Authenticate':'Basic realm="Login required!"'})
   
    #if the above check passes, then we'll reteurn our token!
    token = jwt.encode({'usernmae':auth.username},app.config['SECRET_KEY'])
    
    return jsonify({'token':token.decode('UTF-8')})


@app.route('/api/v1/secret')
def secret():

    token=request.headers['Authorization']

    try:
        jwt.decode(token, app.config['SECRET_KEY'])

    except:
        return Response('Could not decode token',401)

    return jsonify({'message':'This is Secret Data!'})

if __name__=='__main__':
    app.run()